import { fetchSubjectLocation } from "./subjectPropertyFetcher"
import { SubjectProperty } from "@/lib/types/subjectProperty"

export async function buildSubjectProperty(
  address: string,
  purchasePrice: number
): Promise<SubjectProperty> {
  const location = await fetchSubjectLocation(address)

  return {
    address,
    zip: location.zip,
    lat: location.lat,
    lng: location.lng,

    // Phase 1 directional values (acceptable)
    squareFeet: estimateSqft(purchasePrice),
    yearBuilt: 1995,
    beds: 3,
    baths: 2,
    propertyType: "SFR",
    hasGarage: true,
    isBusyStreet: false,
  }
}

function estimateSqft(price: number) {
  if (price < 200000) return 1200
  if (price < 350000) return 1600
  if (price < 500000) return 2000
  return 2400
}
