import { NextResponse } from "next/server"
import Deal from "@/models/Deal"
import { connectDB } from "@/lib/db"
import { getRules } from "@/lib/rules/getRules"
import { evaluateDeal } from "@/lib/engines/dealEvaluator"
import { safeNumber } from "@/lib/utils/safeNumber"
import { mockScrapeSoldProperties } from "@/lib/scraprers/mockScraper"
import { buildSubjectProperty } from "@/lib/services/subjectPropertyBuilder"
import { evaluateComps } from "@/lib/engines/compSelector"
import { requiredCompCount } from "@/lib/engines/domRules"

export async function GET() {
  await connectDB()
  const deals = await Deal.find().sort({ createdAt: -1 })
  return NextResponse.json(deals)
}

export async function POST(req: Request) {
  await connectDB()
  const body = await req.json()
   
  const subject = await buildSubjectProperty(
  body.address,
  body.purchasePrice
)
console.log("value of subject is",subject)

const soldProperties = await mockScrapeSoldProperties(
  subject.zip
)
console.log("value of comp is",soldProperties)
const evaluatedComps = evaluateComps(subject, soldProperties)
console.log("value of included comp is",evaluatedComps)

const includedComps = evaluatedComps.filter((c) => c.included)

console.log("value of included comp is",includedComps)
const minComps = requiredCompCount(body.domDays)

console.log("value of minComps is",minComps)
if (includedComps.length < minComps) {
  return {
    status: "FAIL",
    failureReasons: [
      `Only ${includedComps.length} eligible comps found, ${minComps} required`,
    ],
    comps: evaluatedComps,
  }
}
 return NextResponse.json({
    status: "PASS",
    minRequiredComps: minComps,
    eligibleComps: includedComps.length,
    comps: evaluatedComps,
  })
  const comps = Array.isArray(body.comps) ? body.comps : []

  const rules = await getRules()
  const evaluation = evaluateDeal(body, comps, rules)
console.log("evaluayter:",evaluation);
  const deal = await Deal.create({
    address: body.address,

    purchasePrice: safeNumber(body.purchasePrice),
    arv: safeNumber(evaluation.arv),
    profitPercent: safeNumber(evaluation.profitPercent),

    status: evaluation.status,
    comps: evaluation.comps,
    failureReasons: evaluation.failureReasons,

    source: "MANUAL",
    notes: body.notes ?? "",
  })

  return NextResponse.json(deal)
}
